    /// <param name="e"></param>
    [FormDataSourceEventHandler(formDataSourceStr(VendEditInvoice, VendInvoiceInfoLine), FormDataSourceEventType::Created)]
    public static void VendInvoiceInfoLine_OnCreated(FormDataSource sender, FormDataSourceEventArgs e)
    {
        
        VendinvoiceInfoLine  VendinvoiceInfoLine  = sender.cursor();
        VendinvoiceInfoTable VendinvoiceInfoTable = VendinvoiceInfoLine.vendInvoiceInfoTable();
        str                  dimAttributeName     = DimensionAttribute::UBSGetTableName(tableStr(VendTable),fieldStr(VendTable,AccountNum));

        container conAttribute  = [dimAttributeName];
        container conValue      = [VendinvoiceInfoTable.InvoiceAccount];

        DimensionDefault        newDim    = UBSDefaultDimensionToolKit::createDefaultDimension(conAttribute,conValue);
        LedgerDimensionValueSet mergeDim  = UBSDefaultDimensionToolKit::setDimensionValueToDefaultDimension(VendinvoiceInfoLine.DefaultDimension,newDim,tableStr(VendTable), dimAttributeName);

        VendinvoiceInfoLine.DefaultDimension = mergeDim;
    }

    public void invoiceAccountModified()
    {
        next invoiceAccountModified();
        
        VendinvoiceInfoTable vendinvoiceInfoTable = VendInvoiceInfoTable_ds.cursor();

        str dimAttributeName    = DimensionAttribute::UBSGetTableName(tableStr(VendTable),fieldStr(VendTable,AccountNum));
        container conAttribute  = [dimAttributeName];
        container conValue      = [vendinvoiceInfoTable.InvoiceAccount];

        DimensionDefault        newDim    = UBSDefaultDimensionToolKit::createDefaultDimension(conAttribute,conValue);
        LedgerDimensionValueSet mergeDim  = UBSDefaultDimensionToolKit::setDimensionValueToDefaultDimension(vendinvoiceInfoTable.DefaultDimension,newDim,tableStr(VendTable), dimAttributeName);

        vendinvoiceInfoTable.DefaultDimension = mergeDim;
    }

